mapper.sql:
WITH GHG_DATA_LIST AS ( SELECT /*+ MATERIALZE */ NVL(SUBSTR(AAAA.dscfc_use_de, 0, 6), TO_CHAR(SYSDATE, 'YYYYMM')) AS dscfc_use_de, MAX(AAAA.dscfc_lclhq_cd) AS dscfc_lclhq_cd, MAX(AAAA.dscfc_lclhq_nm) AS dscfc_lclhq_nm, MAX(AAAA.dscfc_bplc_cd) AS dscfc_bplc_cd, MAX(AAAA.dscfc_bplc_nm) AS dscfc_bplc_nm, MAX(AAAA.dscfc_bplc_sort_ordr) AS dscfc_bplc_sort_ordr, MAX(AAAA.dscfc_procs_ty_cd) AS dscfc_procs_ty_cd, MAX(AAAA.dscfc_procs_ty_nm) AS dscfc_procs_ty_nm, AAAA.dscfc_id, MAX(AAAA.dscfc_nm) AS dscfc_nm, MAX(AAAA.dscfc_use_fuel_div_cd) AS dscfc_use_fuel_div_cd, MAX(AAAA.dscfc_use_fuel_div_nm) AS dscfc_use_fuel_div_nm, NVL(ROUND(SUM(AAAA.dscfc_usgqty), 3), 0) AS dscfc_usgqty, /* NVL(SUM(AAAA.dscfc_usgqty), 0) AS tot_usgqty, NVL(SUM(AAAA.sum_dscfc_usgqty), 0) AS sum_dscfc_usgqty, NVL(SUM(AAAA.tot_amt), 0) AS tot_amt, NVL(SUM(AAAA.max_tot_amt), 0) AS max_tot_amt, */ NVL(CASE WHEN SUM(dscfc_usgqty) < 0 AND SUM(tot_amt) > 0 THEN SUM(tot_amt) * -1 ELSE SUM(tot_amt) END, 0) AS tot_amt FROM ( SELECT dscfc_lclhq_cd, dscfc_lclhq_nm, dscfc_bplc_cd, dscfc_bplc_nm, dscfc_bplc_sort_ordr, dscfc_procs_ty_cd, dscfc_procs_ty_nm, ggss_disc_act_div_cd, ggss_disc_act_div_nm, dscfc_ustm_report_trget_yn, dscfc_ustm_report_trget_yn_nm, dscfc_id, dscfc_nm, ipcc_cmbs_ty_cd, ipcc_cmbs_ty_nm, co2_air, ch4_air, n2o_air, energy_usgqty_air, ggss_dsqty_air, dscfc_ser_no, dscfc_nextns_yn, dscfc_nextns_yn_nm, dscfc_use_fuel_div_cd, dscfc_use_fuel_div_nm, dscfc_use_fuel_unit_div_cd, dscfc_use_fuel_unit_div_nm, emsnsrc_rm, emsnsrc_clrval_unit_nm, emsnsrc_clrval_cfcnt, emsnsrc_tot_pyrxia_cfcnt, dscfc_use_de, dscfc_usgqty, sum_dscfc_usgqty, CASE
WHEN max_abs_dscfc_usgqty = 0 AND count_dscfc_use_slip_no > 1 THEN max_tot_amt / count_dscfc_use_slip_no WHEN dscfc_use_slip_prcs_ty_cd != 0 AND (dscfc_usgqty != 0 OR count_dscfc_use_slip_no > 1) THEN (dscfc_usgqty / DECODE(NVL(sum_dscfc_usgqty, 0), 0, 1, sum_dscfc_usgqty)) * max_tot_amt ELSE tot_amt END AS tot_amt, co2_dsqty, ch4_dsqty, n2o_dsqty, cur_co2_gesu, cur_ch4_gesu, cur_n2o_gesu, cur_sanwha_gesu, dscfc_use_slip_prcs_ty_cd, dscfc_use_slip_no FROM ( SELECT /*+ LEADING(BBB EEE FFF AAA) */ AS dscfc_lclhq_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1001' AND cmmn_cd = ) AS dscfc_lclhq_nm, BBB.dscfc_bplc_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1002' AND cmmn_cd = BBB.dscfc_bplc_cd ) AS dscfc_bplc_nm, ( SELECT sort_ordr FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_1002' AND cmmn_cd = BBB.dscfc_bplc_cd ) AS dscfc_bplc_sort_ordr, BBB.dscfc_procs_ty_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0024' AND cmmn_cd = BBB.dscfc_procs_ty_cd ) AS dscfc_procs_ty_nm, BBB.ggss_disc_act_div_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0004' AND cmmn_cd = BBB.ggss_disc_act_div_cd ) AS ggss_disc_act_div_nm, BBB.dscfc_ustm_report_trget_yn, DECODE(BBB.dscfc_ustm_report_trget_yn, 'Y', '사용', '사용중지') AS dscfc_ustm_report_trget_yn_nm, /* paper_yn == cd_use */ BBB.dscfc_id, BBB.dscfc_nm, BBB.ipcc_cmbs_ty_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0002' AND cmmn_cd = BBB.ipcc_cmbs_ty_cd ) AS ipcc_cmbs_ty_nm, DECODE(BBB.ipcc_cmbs_ty_cd, '7', '사용량*CO2배출계수/(1000)', '17', '사용량*CO2배출계수/(1000)', '사용량*(순발열량*100)*CO2배출계수*산화계수/(1000000000)' ) AS co2_air, DECODE(BBB.ipcc_cmbs_ty_cd, '7', '사용량*CH4배출계수/(1000)', '17', '사용량*CH4배출계수/(1000)', '사용량*(순발열량*100)*CH4배출계수*산화계수/(1000000)' ) AS ch4_air, DECODE(BBB.ipcc_cmbs_ty_cd, '7', '사용량*N2O배출계수/(1000)', '17', '사용량*N2O배출계수/(1000)', '사용량*(순발열량*100)*N2O배출계수*산화계수/(1000000)' ) AS n2o_air, 'CO2배출량*CO2지구온난화지수+(CH4배출량*CH4지구온난화지수+N2O배출량*N2O지구온난화지수)/(1000)' AS energy_usgqty_air, '사용량*총발열량' AS ggss_dsqty_air, BBB.dscfc_ser_no, BBB.dscfc_nextns_yn, DECODE(BBB.dscfc_nextns_yn, 'Y', '신증설', 'N', '기존', BBB.dscfc_nextns_yn ) AS dscfc_nextns_yn_nm, BBB.dscfc_use_fuel_div_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0005' AND cmmn_cd = BBB.dscfc_use_fuel_div_cd ) AS dscfc_use_fuel_div_nm, FFF.dscfc_use_fuel_unit_div_cd, ( SELECT cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'SC' AND cls_cd = 'GHG_0006' AND cmmn_cd = FFF.dscfc_use_fuel_unit_div_cd ) AS dscfc_use_fuel_unit_div_nm, /* q.unit AS eng_code, */ EEE.emsnsrc_rm, DECODE(EEE.emsnsrc_nm, '경유', 'TJ/1000M3', '경유(이동)', 'TJ/1000M3', '도시가스(LNG)', 'TJ/10^6M3', '등유', 'TJ/1000M3', '전력', 'TJ/GWH', '휘발유', 'TJ/1000M3', '휘발유(이동)', 'TJ/1000M3', '휘발유(비도로_2)', 'TJ/1000M3', '프로판', 'TJ/GG', '실내등유', 'TJ/1000M3', '부탄', 'TJ/GG', '보일러등유', 'TJ/1000M3', '가스/디젤 오일(경유)', 'TJ/1000M3', 'LPG', 'TJ/GG' ) AS emsnsrc_clrval_unit_nm, EEE.emsnsrc_clrval_cfcnt, EEE.emsnsrc_tot_pyrxia_cfcnt, AAA.dscfc_use_de, NVL(AAA.dscfc_usgqty, 0) AS dscfc_usgqty, SUM(NVL(AAA.dscfc_usgqty, 0)) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS sum_dscfc_usgqty, NVL(AAA.tot_amt, 0) AS tot_amt, MAX(NVL(AAA.tot_amt, 0)) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS max_tot_amt, COUNT(AAA.dscfc_use_slip_no) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS count_dscfc_use_slip_no, MAX(NVL(ABS(AAA.dscfc_usgqty), 0)) OVER(PARTITION BY AAA.dscfc_use_slip_no) AS max_abs_dscfc_usgqty, CASE WHEN BBB.dscfc_use_fuel_div_cd = '61' THEN (NVL(AAA.dscfc_usgqty, '0') * AAA.co2_gesu / 1000) WHEN BBB.dscfc_use_fuel_div_cd <> '61' THEN (NVL(AAA.dscfc_usgqty, '0') / 1000 * EEE.emsnsrc_clrval_cfcnt * AAA.co2_gesu * 1 / 1000000) END AS co2_dsqty, CASE WHEN BBB.dscfc_use_fuel_div_cd = '61' THEN ((NVL(AAA.dscfc_usgqty, '0') * AAA.ch4_gesu * 1000 ) / 1000) WHEN BBB.dscfc_use_fuel_div_cd <> '61' THEN (NVL(AAA.dscfc_usgqty, '0') / 1000 * EEE.emsnsrc_clrval_cfcnt * 1 * AAA.ch4_gesu / 1000) END AS ch4_dsqty, CASE WHEN BBB.dscfc_use_fuel_div_cd = '61' THEN ((NVL(AAA.dscfc_usgqty, '0') * AAA.n2o_gesu * 1000 ) / 1000 ) WHEN BBB.dscfc_use_fuel_div_cd <> '61' THEN (NVL(AAA.dscfc_usgqty, '0') / 1000 * EEE.emsnsrc_clrval_cfcnt * AAA.n2o_gesu * 1 / 1000) END AS n2o_dsqty, AAA.cur_co2_gesu, AAA.cur_ch4_gesu, AAA.cur_n2o_gesu, AAA.cur_sanwha_gesu, AAA.dscfc_use_slip_prcs_ty_cd, AAA.dscfc_use_slip_no FROM GHG.tm_gg01101 BBB, GHG.tm_gg01106 EEE, GHG.te_gg01101 FFF, ( SELECT ABC.dscfc_id, ABC.dscfc_use_de, NVL(MAX(ABC.dscfc_usgqty), 0) AS dscfc_usgqty, NVL(MAX(ABC.tot_amt), 0) AS tot_amt, MAX(ABC.co2_gesu) AS co2_gesu, MAX(ABC.ch4_gesu) AS ch4_gesu, MAX(ABC.n2o_gesu) AS n2o_gesu, MAX(ABC.cur_co2_gesu) AS cur_co2_gesu, MAX(ABC.cur_ch4_gesu) AS cur_ch4_gesu, MAX(ABC.cur_n2o_gesu) AS cur_n2o_gesu, MAX(ABC.cur_sanwha_gesu) AS cur_sanwha_gesu, MAX(ABC.dscfc_use_slip_prcs_ty_cd) AS dscfc_use_slip_prcs_ty_cd, MAX(ABC.dscfc_use_slip_no) AS dscfc_use_slip_no FROM ( SELECT AA.dscfc_id, AA.dscfc_use_de, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.dscfc_usgqty) END AS dscfc_usgqty, CASE WHEN AA.dsqty_cfrml_parm_id IN ('2005', '2001') THEN MAX(AA.tot_amt) END AS tot_amt, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%CO2배출계수' THEN MAX(AA.dscfc_usgqty) END AS co2_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%CH4배출계수' THEN MAX(AA.dscfc_usgqty) END AS ch4_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%N2O배출계수' THEN MAX(AA.dscfc_usgqty) END AS n2o_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%CO2배출계수' AND AA.dsqty_cfrml_parm_end_de = '99991231' THEN MAX(AA.dsqty_cfrml_parm_vu) END AS cur_co2_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%CH4배출계수' AND AA.dsqty_cfrml_parm_end_de = '99991231' THEN MAX(AA.dsqty_cfrml_parm_vu) END AS cur_ch4_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%N2O배출계수' AND AA.dsqty_cfrml_parm_end_de = '99991231' THEN MAX(AA.dsqty_cfrml_parm_vu) END AS cur_n2o_gesu, CASE WHEN AA.dsqty_cfrml_parm_nm LIKE '%산화계수' AND AA.dsqty_cfrml_parm_end_de = '99991231' THEN MAX(AA.dsqty_cfrml_parm_vu) END AS cur_sanwha_gesu, MAX(AA.dscfc_use_slip_prcs_ty_cd) AS dscfc_use_slip_prcs_ty_cd, MAX(AA.dscfc_use_slip_no) AS dscfc_use_slip_no FROM ( SELECT A.dscfc_id, A.dscfc_use_de, B.dsqty_cfrml_parm_id, B.dsqty_cfrml_parm_nm, A.dscfc_use_slip_prcs_ty_cd, A.dscfc_use_slip_no, A.dscfc_usgqty, A.tot_amt, /* B.dsqty_cfrml_parm_vu, */ C.dsqty_cfrml_parm_vu, C.dsqty_cfrml_parm_end_de FROM GHG.tm_rq01103 A, GHG.tm_gg01104 B, GHG.td_gg01102 C WHERE ( (A.dscfc_use_slip_no IS NOT NULL AND A.dscfc_use_slip_no NOT LIKE 'TMP%') OR A.dscfc_use_slip_prcs_ty_cd = '1' ) AND ( B.dsqty_cfrml_parm_nm LIKE '%CH4배출계수' OR B.dsqty_cfrml_parm_nm LIKE '%CO2배출계수' OR B.dsqty_cfrml_parm_nm LIKE '%N2O배출계수' OR A.dsqty_cfrml_parm_id IN ('2005', '2001') ) AND A.dscfc_use_de BETWEEN NVL(SUBSTR(#{strtDt}, 0, 4), TO_CHAR(SYSDATE, 'YYYY')) || '0101' AND NVL(SUBSTR(#{endDt}, 0, 4), TO_CHAR(SYSDATE, 'YYYY')) || '1231' AND A.dsqty_cfrml_parm_id = B.dsqty_cfrml_parm_id AND B.dsqty_cfrml_parm_id = C.dsqty_cfrml_parm_id ) AA GROUP BY AA.dscfc_id, AA.dscfc_use_de, AA.dsqty_cfrml_parm_id, AA.dsqty_cfrml_parm_nm, AA.dsqty_cfrml_parm_end_de ) ABC GROUP BY ABC.dscfc_id, ABC.dscfc_use_de ) AAA WHERE BBB.dscfc_id = AAA.dscfc_id(+) AND BBB.dscfc_use_fuel_div_cd = FFF.dscfc_use_fuel_div_cd AND EEE.emsnsrc_id = FFF.emsnsrc_id /* AND n.fuel_code = q.code(+) */ AND BBB.dscfc_use_yn = '1' AND BBB.dscfc_regist_stat_div_cd = '1' AND BBB.dscfc_use_fuel_div_cd = '61' /* 전기 */
/* AND BBB.dscfc_use_fuel_unit_div_nm = '㎾h' */ AND BBB.dscfc_lclhq_cd != '88888888' /* 위탁 */
AND = ( SELECT objid FROM (
) WHERE cmmn_cd = #{ecsBasinDivCd} )
) ) AAAA GROUP BY SUBSTR(AAAA.dscfc_use_de, 0, 6), AAAA.dscfc_id ORDER BY dscfc_use_de, dscfc_lclhq_nm, dscfc_bplc_nm, dscfc_nm )

mapper.select:
/* CNSMP_STTUS_Dao_retrieveCnsmpSttusChart */
SELECT MAX(dscfc_bplc_nm) AS dscfc_bplc_nm, ROUND(NVL(SUM(dscfc_usgqty), 0), 2) AS inqire_iem_vu FROM GHG_DATA_LIST WHERE 1 = 1
AND dscfc_use_de BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6)
AND dscfc_bplc_cd = #{ecsChrgDeptId}
GROUP BY dscfc_bplc_cd UNION ALL SELECT dscfc_nm, inqire_iem_vu FROM ( SELECT MAX(dscfc_nm) AS dscfc_nm, SUM(dscfc_usgqty) AS inqire_iem_vu FROM GHG_DATA_LIST WHERE 1 = 1
AND dscfc_use_de BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6)
AND dscfc_bplc_cd = #{ecsChrgDeptId}
GROUP BY dscfc_bplc_cd, dscfc_id ORDER BY dscfc_nm )
